import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class UserApiClient {

    private static final String BASE_URL_DEVELOPMENT = "https://api.example.com/";
    private static final String BASE_URL_STAGING = "https://staging.api.example.com/";
    private static final String BASE_URL_PRODUCTION = "https://prod.api.example.com/";

    private ApiService apiService;

    public UserApiClient(String environment) {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(getBaseUrl(environment))
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        apiService = retrofit.create(ApiService.class);
    }

    private String getBaseUrl(String environment) {
        switch (environment.toLowerCase()) {
            case "development":
                return BASE_URL_DEVELOPMENT;
            case "staging":
                return BASE_URL_STAGING;
            case "production":
                return BASE_URL_PRODUCTION;
            default:
                throw new IllegalArgumentException("Invalid environment");
        }
    }

    public void fetchUsers(Callback<UserResponse> callback) {
        Call<UserResponse> call = apiService.getUsers();
        call.enqueue(callback);
    }

    interface ApiService {
        @GET("users")
        Call<UserResponse> getUsers();
    }

    static class UserResponse {
        private List<User> users;

        // Getters and setters
        public List<User> getUsers() {
            return users;
        }

        public void setUsers(List<User> users) {
            this.users = users;
        }
    }

    static class User {
        private String id;
        private String name;

        // Getters and setters
        public String getId() {
            return id;
        }

        public void setId(String id) {
            this.id = id;
        }

        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }
    }
}